{
  "compilerOptions": {
    // Version JS produite
    "target": "ES2020",

    // Système de modules
    "module": "ESNext",
    "moduleResolution": "bundler",

    // Active toutes les vérifications strictes
    "strict": true,

    // Interop avec les modules CommonJS
    "esModuleInterop": true,

    // Dossier de sortie
    "outDir": "./dist",

    // Inclure les types DOM (pour le navigateur)
    "lib": ["ES2020", "DOM"],

    // Vérifications supplémentaires utiles
    "noUnusedLocals": true,
    "noUnusedParameters": true,
    "exactOptionalPropertyTypes": true
  },
  "include": ["src/**/*"],
  "exclude": ["node_modules", "dist"]
}
